+  iframe.srcdoc = escapeHtml(sanitizedUrl);
   iframe.style.width = "100%";
   iframe.style.height = "100%";
   iframe.style.border = "none";
   iframe.style.overflow = "hidden";
   container.appendChild(iframe);
   return iframe;
 };

+const isSameOriginEmbed = (url: string): boolean => {
+  try {
+    const urlObj = new URL(url);
+    // Only allow same-origin for trusted embed domains
+    const trustedDomains = ["gist.github.com", "docs.google.com", "www.youtube.com"];
+    return trustedDomains.some(domain => urlObj.hostname.endsWith(domain));
+  } catch {
+    return false;
+  }
+};
+
 export const sanitizeUrl = (url: string): string => {
   try {
     const urlObj = new URL(url);
-    return urlObj.href;
+    // Remove any script tags or event handlers from the URL
+    const cleanUrl = urlObj.href
+      .replace(/<[^>]*>/g, "")
+      .replace(/on\w+\s*=/gi, "")
+      .replace(/javascript:/gi, "");
+    return cleanUrl;
+  } catch {
+    return "";
+  }
 };

